previewCss:
.darma-loader-uiverse-ruby-chevron-shine {
  position: relative;
  width: 200px;
  height: 200px;
}

.darma-loader-uiverse-ruby-chevron-shine .darma-loader-uiverse-ruby-chevron-shine__pattern-1 {
position: absolute;
background-color: #ff4c5a;
width: 200px;
height: 200px;
clip-path: polygon(0 10%, 70% 90%, 40% 90%, 0 45%);
}

.darma-loader-uiverse-ruby-chevron-shine .darma-loader-uiverse-ruby-chevron-shine__pattern-2 {
position: absolute;
background-color: #ff4c5a;
width: 220px;
height: 190px;
clip-path: polygon(100% 10%, 100% 45%, 83% 65%, 55% 65%);
}

.darma-loader-uiverse-ruby-chevron-shine .darma-loader-uiverse-ruby-chevron-shine__pattern-1 .darma-loader-uiverse-ruby-chevron-shine__pattern-1-shade {
position: absolute;
transform: translateX(-20px);
opacity: 0.7;
z-index: 10;
background-color: white;
width: 20px;
height: 200px;
animation: darma-loader-uiverse-ruby-chevron-shine-shiny 1s infinite;
}

@keyframes darma-loader-uiverse-ruby-chevron-shine-shiny {
0% {
transform: translateX(-20px);
}
100% {
transform: translateX(140px);
}
}

